5041 bool CmpInst::isImpliedTrueByMatchingCmp(Predicate Pred1, Predicate Pred2) {
5042   // If the predicates match, then we know the first condition implies the
5043   // second is true.
5044   if (Pred1 == Pred2)
5045     return true;
5046 
5047   switch (Pred1) {
5048   default:
5049     break;
5050   case ICMP_EQ:
5051     // A == B implies A >=u B, A <=u B, A >=s B, and A <=s B are true.
5052     return Pred2 == ICMP_UGE || Pred2 == ICMP_ULE || Pred2 == ICMP_SGE ||
5053            Pred2 == ICMP_SLE;
5054   case ICMP_UGT: // A >u B implies A != B and A >=u B are true.
5055     return Pred2 == ICMP_NE || Pred2 == ICMP_UGE;
5056   case ICMP_ULT: // A <u B implies A != B and A <=u B are true.
5057     return Pred2 == ICMP_NE || Pred2 == ICMP_ULE;
5058   case ICMP_SGT: // A >s B implies A != B and A >=s B are true.
5059     return Pred2 == ICMP_NE || Pred2 == ICMP_SGE;
5060   case ICMP_SLT: // A <s B implies A != B and A <=s B are true.
5061     return Pred2 == ICMP_NE || Pred2 == ICMP_SLE;
5062   }
5063   return false;
5064 }
